evaluators.evaluation_logic:
const checkpoints = [];

let bookings = [];
try {
  bookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]');
} catch (e) {
  bookings = [];
}

const qualifyingBookings = bookings.filter(b => {
  if (!b) return false;
  if (b.serviceType !== 'ai_strategy_consultation') return false;
  if (b.industry !== 'manufacturing') return false;
  if (b.durationMinutes !== 60) return false;
  if (b.participantsCount !== 5) return false;
  if (b.budgetRange !== '10k_25k') return false;
  if (!b.scheduledStart) return false;
  const d = new Date(b.scheduledStart);
  if (isNaN(d.getTime())) return false;
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1; // 1-12
  const hour = d.getUTCHours();
  if (year !== 2026 || month !== 10) return false;
  // Afternoon window 12:00–17:59 UTC
  if (hour < 12 || hour > 17) return false;
  return true;
});

// Single checkpoint: user created at least one fully qualifying booking
checkpoints.push({ passed: qualifyingBookings.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let offerings = [];
let proposals = [];
try {
  offerings = JSON.parse(localStorage.getItem('consulting_offerings') || '[]');
} catch (e) {
  offerings = [];
}
try {
  proposals = JSON.parse(localStorage.getItem('proposal_requests') || '[]');
} catch (e) {
  proposals = [];
}

const eligibleOfferings = offerings.filter(o => {
  if (!o || o.status !== 'active') return false;
  if (o.offeringType !== 'ai_transformation_package') return false;
  if (o.targetCompanySizeSegment !== 'mid_size') return false;
  if (typeof o.price !== 'number' || o.price > 12000) return false;
  if (!o.includesWorkshops) return false;
  if (typeof o.workshopsCount !== 'number' || o.workshopsCount < 2) return false;
  return true;
});

const eligibleIds = eligibleOfferings.map(o => o.id);

const qualifyingProposals = proposals.filter(pr => {
  if (!pr) return false;
  if (!eligibleIds.includes(pr.offeringId)) return false;
  if (typeof pr.companySizeEmployees !== 'number') return false;
  // mid-size band ~101–500 employees
  if (pr.companySizeEmployees < 101 || pr.companySizeEmployees > 500) return false;
  if (!pr.desiredStartDate) return false;
  const d = new Date(pr.desiredStartDate);
  if (isNaN(d.getTime())) return false;
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1;
  if (year !== 2026 || month !== 9) return false; // around September 2026
  return true;
});

// Single checkpoint: at least one proposal for a qualifying mid-size package with a September 2026 start
checkpoints.push({ passed: qualifyingProposals.length >= 1, weight: 1.0 });

return checkPoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let caseStudies = [];
let savedItems = [];
try {
  caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
} catch (e) {
  caseStudies = [];
}
try {
  savedItems = JSON.parse(localStorage.getItem('saved_items') || '[]');
} catch (e) {
  savedItems = [];
}

const qualifyingCaseStudyIds = caseStudies
  .filter(cs => {
    if (!cs) return false;
    if (cs.industry !== 'retail_ecommerce') return false;
    if (typeof cs.year !== 'number' || cs.year < 2022 || cs.year > 2026) return false;
    if (typeof cs.roiPercent !== 'number' || cs.roiPercent < 20) return false;
    if (typeof cs.projectDurationMonths !== 'number' || cs.projectDurationMonths > 5) return false; // under 6 months
    return true;
  })
  .map(cs => cs.id);

const qualifyingSaved = savedItems.filter(s => {
  if (!s) return false;
  if (s.listType !== 'reading_list') return false;
  if (s.contentType !== 'case_study') return false;
  if (!qualifyingCaseStudyIds.includes(s.contentId)) return false;
  return true;
});

// Checkpoints reward only qualifying case studies saved to the reading list
[1, 2, 3].forEach((n, index) => {
  const weight = n === 1 ? 0.34 : 0.33;
  checkpoints.push({ passed: qualifyingSaved.length >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let sessions = [];
let options = [];
let offerings = [];
let bookings = [];

try { sessions = JSON.parse(localStorage.getItem('ai_readiness_assessment_sessions') || '[]'); } catch (e) { sessions = []; }
try { options = JSON.parse(localStorage.getItem('ai_readiness_options') || '[]'); } catch (e) { options = []; }
try { offerings = JSON.parse(localStorage.getItem('consulting_offerings') || '[]'); } catch (e) { offerings = []; }
try { bookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]'); } catch (e) { bookings = []; }

const optionById = {};
options.forEach(o => { if (o && o.id) optionById[o.id] = o; });

const questionIds = [
  'company_size',
  'data_infrastructure_maturity',
  'ai_experience_level',
  'ai_budget_commitment',
  'leadership_support',
  'technical_skillset'
];

const questionInfo = {};
questionIds.forEach(qid => {
  const qOptions = options.filter(o => o && o.questionId === qid && typeof o.score === 'number');
  if (qOptions.length > 0) {
    let min = Infinity;
    let max = -Infinity;
    qOptions.forEach(o => {
      if (o.score < min) min = o.score;
      if (o.score > max) max = o.score;
    });
    const midOptions = qOptions.filter(o => o.score > min && o.score < max);
    questionInfo[qid] = {
      minScore: min,
      maxScore: max,
      midOptionIds: midOptions.map(o => o.id)
    };
  }
});

const strategyOfferings = offerings.filter(o => o && o.status === 'active' && o.offeringType === 'ai_strategy_service' && typeof o.price === 'number');
let cheapestStrategyOffering = null;
if (strategyOfferings.length > 0) {
  cheapestStrategyOffering = strategyOfferings.reduce((cheapest, o) => (o.price < cheapest.price ? o : cheapest), strategyOfferings[0]);
}

const midRangeSessions = sessions.filter(sess => {
  if (!sess || !Array.isArray(sess.answerOptionIds)) return false;
  const selectedOptions = sess.answerOptionIds.map(id => optionById[id]).filter(Boolean);

  // Ensure mid-range selection for each key question
  for (let i = 0; i < questionIds.length; i++) {
    const qid = questionIds[i];
    const qInfo = questionInfo[qid];
    if (!qInfo || !Array.isArray(qInfo.midOptionIds) || qInfo.midOptionIds.length === 0) return false;
    const selectedForQ = selectedOptions.filter(o => o.questionId === qid);
    if (selectedForQ.length === 0) return false;
    const hasMid = selectedForQ.some(o => qInfo.midOptionIds.includes(o.id));
    if (!hasMid) return false;
  }

  // Overall readiness level should be medium
  if (sess.readinessLevel !== 'medium') return false;

  // Recommended offering should be the cheapest active AI strategy service
  if (!sess.recommendedOfferingId || !cheapestStrategyOffering) return false;
  if (sess.recommendedOfferingId !== cheapestStrategyOffering.id) return false;

  return true;
});

// CP1: At least one assessment session with mid-range answers and correct recommended offering
checkpoints.push({ passed: midRangeSessions.length > 0, weight: 0.4 });

// CP2: A consultation booking exists that follows the recommended offering from such a session
let hasFollowupBooking = false;
if (midRangeSessions.length > 0) {
  const recoIds = midRangeSessions.map(s => s.recommendedOfferingId).filter(Boolean);
  const followup = bookings.find(b => b && recoIds.includes(b.offeringId));
  if (followup) hasFollowupBooking = true;
}
checkpoints.push({ passed: hasFollowupBooking, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let events = [];
let registrations = [];
let baselineDate = null;

try { events = JSON.parse(localStorage.getItem('events') || '[]'); } catch (e) { events = []; }
try { registrations = JSON.parse(localStorage.getItem('event_registrations') || '[]'); } catch (e) { registrations = []; }

try {
  const meta = JSON.parse(localStorage.getItem('_metadata') || 'null');
  if (meta && meta.baselineDate) baselineDate = new Date(meta.baselineDate);
} catch (e) {}
if (!baselineDate) baselineDate = new Date();

const baseYear = baselineDate.getUTCFullYear();
const baseMonth = baselineDate.getUTCMonth();
const nextMonth = baseMonth === 11 ? 0 : baseMonth + 1;
const nextYear = baseMonth === 11 ? baseYear + 1 : baseYear;

const qualifyingRegs = registrations.filter(reg => {
  if (!reg || !reg.eventId) return false;
  const ev = events.find(e => e && e.id === reg.eventId);
  if (!ev) return false;
  const d = new Date(ev.startDateTime);
  if (isNaN(d.getTime())) return false;

  // Next month relative to baseline
  if (d.getUTCFullYear() !== nextYear || d.getUTCMonth() !== nextMonth) return false;

  // Online webinar
  if (ev.format !== 'webinar') return false;
  if (ev.deliveryMode !== 'online') return false;
  if (ev.status !== 'upcoming') return false;

  // Time window 11:00–15:59 UTC
  const hour = d.getUTCHours();
  if (hour < 11 || hour > 15) return false;

  // GenAI + marketing focus
  const title = (ev.title || '').toLowerCase();
  const desc = (ev.description || '').toLowerCase();
  const tags = Array.isArray(ev.tags) ? ev.tags.join(' ').toLowerCase() : '';
  const topic = (ev.topicCategory || '').toLowerCase();
  const hasGenAI = title.includes('genai') || desc.includes('genai') || tags.includes('genai') || topic.includes('genai');
  const hasMarketing = title.includes('marketing') || desc.includes('marketing') || tags.includes('marketing') || topic.includes('marketing');
  if (!hasGenAI || !hasMarketing) return false;

  // Basic attendee info must be present
  if (!reg.attendeeName || !reg.attendeeEmail) return false;

  return true;
});

// Single checkpoint: at least one qualifying registration
checkpoints.push({ passed: qualifyingRegs.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let estimates = [];
let offerings = [];
let proposals = [];

try { estimates = JSON.parse(localStorage.getItem('project_estimates') || '[]'); } catch (e) { estimates = []; }
try { offerings = JSON.parse(localStorage.getItem('consulting_offerings') || '[]'); } catch (e) { offerings = []; }
try { proposals = JSON.parse(localStorage.getItem('proposal_requests') || '[]'); } catch (e) { proposals = []; }

const qualifyingEstimates = estimates.filter(e => {
  if (!e) return false;
  if (e.industry !== 'financial_services') return false;
  if (!Array.isArray(e.engagementScope)) return false;
  if (!e.engagementScope.includes('strategy_roadmap') || !e.engagementScope.includes('implementation')) return false;
  if (!Array.isArray(e.modules)) return false;
  if (!e.modules.includes('data_audit') || !e.modules.includes('team_training')) return false;
  if (e.modules.includes('mlops_setup')) return false;
  if (e.teamSize !== 8) return false;
  if (e.timelineWeeks !== 16) return false;
  if (typeof e.budgetMin !== 'number' || e.budgetMin < 100000) return false;
  if (typeof e.budgetMax !== 'number' || e.budgetMax > 250000) return false;
  return true;
});

const qualifyingEstimateIds = qualifyingEstimates.map(e => e.id);

const qualifyingProposals = proposals.filter(pr => {
  if (!pr) return false;
  if (!qualifyingEstimateIds.includes(pr.estimateId)) return false;
  const off = offerings.find(o => o && o.id === pr.offeringId);
  if (!off) return false;
  if (off.offeringType !== 'ai_transformation_package') return false;
  if (off.industry_focus !== 'financial_services') return false; // FS-specific program
  if (!pr.desiredStartDate) return false;
  const d = new Date(pr.desiredStartDate);
  if (isNaN(d.getTime())) return false;
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1;
  if (year !== 2026 || month !== 5) return false; // around May 2026
  return true;
});

// Single checkpoint: at least one proposal linked to a fully qualifying estimate and FS end-to-end offering
checkpoints.push({ passed: qualifyingProposals.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let posts = [];
let savedItems = [];
let baselineDate = null;

try { posts = JSON.parse(localStorage.getItem('blog_posts') || '[]'); } catch (e) { posts = []; }
try { savedItems = JSON.parse(localStorage.getItem('saved_items') || '[]'); } catch (e) { savedItems = []; }

try {
  const meta = JSON.parse(localStorage.getItem('_metadata') || 'null');
  if (meta && meta.baselineDate) baselineDate = new Date(meta.baselineDate);
} catch (e) {}
if (!baselineDate) baselineDate = new Date();

const startRange = new Date(baselineDate.getTime());
startRange.setMonth(startRange.getMonth() - 12);

const qualifyingPostIds = posts
  .filter(p => {
    if (!p) return false;
    if (p.topicCategory !== 'governance_ethics') return false;
    if (typeof p.estimatedReadTimeMinutes !== 'number' || p.estimatedReadTimeMinutes >= 10) return false;
    const d = new Date(p.publishDate);
    if (isNaN(d.getTime())) return false;
    if (d < startRange || d > baselineDate) return false;
    // Ensure clear AI governance relevance via keyword
    const text = ((p.title || '') + ' ' + (p.summary || '') + ' ' + (p.body || '')).toLowerCase();
    const tags = Array.isArray(p.tags) ? p.tags.join(' ').toLowerCase() : '';
    const hasKeyword = text.includes('ai governance') || tags.includes('ai governance');
    if (!hasKeyword) return false;
    return true;
  })
  .map(p => p.id);

const qualifyingSaved = savedItems.filter(s => {
  if (!s) return false;
  if (s.listType !== 'reading_queue') return false;
  if (s.contentType !== 'blog_post') return false;
  if (!qualifyingPostIds.includes(s.contentId)) return false;
  return true;
});

[1, 2, 3].forEach(n => {
  const weight = n === 1 ? 0.34 : 0.33;
  checkpoints.push({ passed: qualifyingSaved.length >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let programs = [];
let bookings = [];

try { programs = JSON.parse(localStorage.getItem('training_programs') || '[]'); } catch (e) { programs = []; }
try { bookings = JSON.parse(localStorage.getItem('training_booking_requests') || '[]'); } catch (e) { bookings = []; }

const eligiblePrograms = programs.filter(p => {
  if (!p) return false;
  if (p.status !== 'active') return false;
  if (p.deliveryFormat !== 'remote') return false;
  if (p.region !== 'europe_emea') return false;
  if (typeof p.price !== 'number' || p.price > 8000) return false;
  if (typeof p.liveSessionsCount !== 'number' || p.liveSessionsCount < 2) return false;
  if (typeof p.minParticipants === 'number' && p.minParticipants > 30) return false;
  if (typeof p.maxParticipants === 'number' && p.maxParticipants < 30) return false;
  return true;
});

let cheapestProgram = null;
if (eligiblePrograms.length > 0) {
  cheapestProgram = eligiblePrograms.reduce((cheapest, p) => (p.price < cheapest.price ? p : cheapest), eligiblePrograms[0]);
}

const qualifyingBookings = bookings.filter(b => {
  if (!cheapestProgram || !b) return false;
  if (b.trainingProgramId !== cheapestProgram.id) return false;

  // Participants ~30 (allow small tolerance)
  if (typeof b.participantsCount === 'number') {
    if (b.participantsCount < 25 || b.participantsCount > 35) return false;
  }

  const notes = (b.notes || '').toLowerCase();
  const hasKeywords = ['30-person', 'european', 'sales team'].every(kw => notes.includes(kw.toLowerCase()));
  if (!hasKeywords) return false;

  if (!b.contactName || !b.contactEmail) return false;
  const email = b.contactEmail.toLowerCase();
  const emailDomainOk = email.endsWith('@example.com') || email.endsWith('.example.com');
  if (!emailDomainOk) return false;

  return true;
});

// Single checkpoint: booking request exists for the cheapest qualifying program with correct team details
checkpoints.push({ passed: qualifyingBookings.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
